/**
 * Settings Overrides — M168 Phase 4 (#1914)
 *
 * Per-session settings overrides backed by the `settings_overrides` table
 * in the shared SQLite session DB. Each row is keyed by (sid, key) so two
 * sessions can hold mutually-invisible overrides for the same key (e.g.
 * `effort=high` for session A while session B keeps `effort=medium`).
 *
 * Layer 4 of the 4-layer coordination architecture (#1908). Reads are
 * lock-free (WAL); writes serialize through writeWithRetry / BEGIN IMMEDIATE.
 *
 * Schema (see sqlite-migrations/001-initial.sql):
 *
 *   CREATE TABLE settings_overrides (
 *     sid              TEXT NOT NULL REFERENCES sessions(sid) ON DELETE CASCADE,
 *     key              TEXT NOT NULL,
 *     value            TEXT NOT NULL,
 *     set_at           INTEGER NOT NULL,
 *     PRIMARY KEY (sid, key)
 *   );
 *
 * ON DELETE CASCADE means a session's overrides disappear automatically when
 * the parent session row is deleted; we never need to clean them manually.
 */

import { getOrCreateDb, writeWithRetry } from './session-registry.js';

/** A single row from `settings_overrides`. */
export interface SettingsOverrideEntry {
  key: string;
  value: string;
}

/**
 * Read the override value for (sid, key). Returns `null` when no row exists.
 * Plain prepared SELECT — WAL allows concurrent readers without serializing.
 */
export function getOverride(sid: string, key: string): string | null {
  const db = getOrCreateDb();
  const row = db
    .prepare('SELECT value FROM settings_overrides WHERE sid = ? AND key = ?')
    .get(sid, key) as { value: string } | undefined;
  return row ? row.value : null;
}

/**
 * Insert-or-replace the override for (sid, key). Wrapped in writeWithRetry
 * so SQLITE_BUSY at BEGIN IMMEDIATE retries up to 15× with jittered backoff.
 */
export function setOverride(sid: string, key: string, value: string): void {
  const now = Math.floor(Date.now() / 1000);
  writeWithRetry(db => {
    db.prepare(
      `INSERT INTO settings_overrides (sid, key, value, set_at)
       VALUES (?, ?, ?, ?)
       ON CONFLICT(sid, key) DO UPDATE SET
         value  = excluded.value,
         set_at = excluded.set_at`,
    ).run(sid, key, value, now);
  });
}

/** Remove the override for (sid, key). No-op when the row is absent. */
export function deleteOverride(sid: string, key: string): void {
  writeWithRetry(db => {
    db.prepare(
      'DELETE FROM settings_overrides WHERE sid = ? AND key = ?',
    ).run(sid, key);
  });
}

/** Return every (key, value) override row for the given session. */
export function listOverrides(sid: string): SettingsOverrideEntry[] {
  const db = getOrCreateDb();
  return db
    .prepare('SELECT key, value FROM settings_overrides WHERE sid = ? ORDER BY key')
    .all(sid) as unknown as SettingsOverrideEntry[];
}
